/**
 * @param {number[]} arr
 * @return {number}
 */
var maximumElementAfterDecrementingAndRearranging = function(arr) {
    const n = arr.length;
    const dp = new Array(n + 1).fill(0);

    for (const num of arr) {
        dp[Math.min(num, n)]++;
    }

    let res = n;
    let cur = 0;

    for (let i = n; i >= 1; i--) {
        if (dp[i] > 0) {
            cur += dp[i] - 1;
            continue;
        }

        if (cur > 0) {
            cur--;
        } else {
            res--;
        }
    }

    return res;
};

/**
 * @param {number[]} arr
 * @return {number}
 */
var maximumElementAfterDecrementingAndRearranging = function(arr) {
    arr.sort((a, b) => a - b);

    let pos = 0;

    for (const num of arr) {
        if (num > pos) {
            pos++;
        }
    }

    return pos;
};
